#!/usr/bin/env python3
"""
MKT Original — Amos chapters 6–9
Run: python3 scripts/zc-original-amos-6-9-full.py

Key translation decisions:
- sha'ananim (6:1): complacent/at ease — the false security of the privileged
- anakh (7:7-9): plumb line — the only OT use of this Akkadian loanword (anakku = lead/tin)
- kayits/qets (8:1-2): summer fruit / end — pun on ripeness and termination
- sukat David (9:11): booth/hut of David — deliberately humble; sukkah not palace or temple
- 9:12 MT yadreshu et she'erit Edom (possess remnant of Edom) vs LXX ekzetesousin ton kurion (seek the Lord)
  Acts 15:17 cites LXX — the textual divergence is exegetically significant
"""

import json
from pathlib import Path

ROOT = Path(__file__).resolve().parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

AMOS = {
    "6": {
        "1": "<p><strong>hoy hasha&apos;ananim b&apos;Tzion</strong> — &quot;Woe to those who are complacent in Zion.&quot; <em>Sha&apos;ananim</em> (at ease, complacent, undisturbed) describes those whose tranquility is groundless self-confidence. The woe formula (<em>hoy</em>) marks a funeral lament directed at the living — the recipients are being mourned before their death arrives. Zion and Samaria are addressed together, the twin capitals of divided Israel, their residents imagined as &quot;notable men of the first of the nations&quot; — a bitter irony, since status in human ranking counts for nothing in the coming reversal.</p>",
        "2": "<p><strong>Calneh, Hamath, Gath</strong> — Amos summons Israel to survey the great cities that have fallen: Calneh in Assyria, Hamath on the Orontes, Gath of the Philistines. The rhetorical question &quot;Are they better than these kingdoms?&quot; points to conquered territories as the destiny awaiting the complacent. The cities named were major powers within living memory — their downfall provides a warning Israel is refusing to read.</p>",
        "3": "<p><strong>ha-menaddim l&apos;yom ra</strong> — &quot;those who put off the day of disaster.&quot; The participle <em>menaddim</em> suggests a pushing-away or postponing — the complacent actively suppress awareness of coming judgment. Meanwhile they &quot;bring near a seat of violence,&quot; the very thing they pretend is far off. The inversion — distancing the day of reckoning while drawing violence near — captures the self-defeating logic of complacency.</p>",
        "4": "<p><strong>ha-shokevim al mitot shein</strong> — &quot;those who lie on beds of ivory.&quot; Archaeological finds at Samaria confirm ivory-inlaid furniture among the elite. The participles in vv. 4-6 accumulate to build a portrait of sensory indulgence: lying, sprawling, eating lambs from the flock, eating calves from the stall — animals chosen for their tenderness, animals that belong to others. The food imagery is abundance stripped of gratitude.</p>",
        "5": "<p><strong>ha-poretin al pi ha-nevel</strong> — &quot;those who improvise to the sound of the lyre.&quot; <em>Poretin</em> (improvising, strumming idly) has a pejorative edge — the music is self-entertainment without purpose. The comparison to David is audacious: David played before YHWH in lament and praise; these players invent instruments for self-pleasure. The same cultural material (music, instruments) serves opposite ends depending on orientation.</p>",
        "6": "<p><strong>ha-shotim b&apos;mizraqei yain</strong> — &quot;those who drink wine in bowls (mizraqim).&quot; <em>Mizraq</em> normally designates the sacrificial basin used in temple ritual — drinking from such vessels suggests the sacred has been domesticated as luxury. Anointing with the finest oils compounds the sensory portrait. The indictment's climax: &quot;they are not grieved over the ruin of Joseph&quot; (<em>shever Yosef</em>) — the covenant community is collapsing and the elite feel nothing. <em>Shever</em> means fracture, destruction — the exact word used for the destruction Amos announces.</p>",
        "7": "<p><strong>laken ata yiglu b&apos;rosh golim</strong> — &quot;therefore they shall now be the first to go into exile.&quot; The irony is precise: those who claimed to be &quot;the first of the nations&quot; (v. 1) will be the first to go into exile. The verb <em>galah</em> (go into exile, uncover) is the covenant punishment for covenant violation. The &quot;revelry of those who sprawl&quot; (<em>mirzah ha-seruhim</em>) will end — <em>mirzah</em> is a cultic feast associated with the dead, a term of association found in Ugaritic texts as well, suggesting a quasi-cultic character to these gatherings.</p>",
        "8": "<p><strong>nishba Adonai bi-nafshō</strong> — &quot;the Lord YHWH swears by himself.&quot; When YHWH swears by himself (<em>nishba bi-nafshō</em>, literally &quot;by his soul/being&quot;), the oath is absolute — there is no higher authority by which to guarantee it. The object of divine loathing is <em>ge&apos;on Yaakov</em> (&quot;the pride of Jacob&quot;) — the same pride elsewhere celebrated as divine gift has become, through self-congratulatory complacency, the thing YHWH finds abhorrent.</p>",
        "9": "<p><strong>im yivateru asara anashim</strong> — &quot;if ten men remain in a single house, they shall die.&quot; The decimation scenario underscores totality of judgment — even small surviving clusters will not escape. The verse prepares for the strange scene in v. 10, where survivors are afraid even to mention the name of YHWH in connection with the dead.</p>",
        "10": "<p><strong>al tazker b&apos;shem YHWH</strong> — &quot;do not invoke the name of YHWH.&quot; When a kinsman comes to carry out a corpse and asks if others are present, the survivor says &quot;No&quot; — and adds, &quot;Silence! We must not invoke the name of YHWH.&quot; The motive is terror: the divine name, which in times of blessing is the source of protection, has become in times of judgment an additional danger to invoke. The reversal of the name&apos;s function signals total covenant breakdown.</p>",
        "11": "<p><strong>ki hineh YHWH metzaveh</strong> — &quot;for YHWH is commanding.&quot; The present participle <em>metzaveh</em> gives the judgment a quality of immediacy — not future but already in process. The great house will be struck into rubble (<em>breaches</em>, <em>reshim</em>) and the small house into splinters. The completeness of the destruction makes no distinction between wealth levels: both great and small houses are equally vulnerable when the divine command goes forth.</p>",
        "12": "<p><strong>hayerutzun ba-sela susim</strong> — &quot;Can horses gallop on bare rock?&quot; The rhetorical questions establish logical impossibility: horses cannot gallop on rock, one cannot plow rock with oxen. Yet Israel has done something equally impossible and self-defeating — turning <em>mishpat</em> (justice, the grain that sustains life) into <em>rosh</em> (poison/bitter herb) and the fruit of <em>tzedaqah</em> (righteousness) into <em>laanah</em> (wormwood). The perversion of justice defies the same logic as perverting nature.</p>",
        "13": "<p><strong>ha-simechim l&apos;Lo-davar</strong> — &quot;those who rejoice in Lo-dabar.&quot; Lo-dabar means &quot;nothing, no-thing&quot; — a town east of the Jordan that Israel treats as a military achievement. <em>Qarnayim</em> (&quot;two horns&quot;) likewise sounds like a military trophy, but <em>qarnayim</em> also means horns of an animal — symbols of strength they have acquired by &quot;our own strength.&quot; The boast is double-edged: the places of supposed triumph are wordplays on nothing and animal strength, undermining the confidence they inspire.</p>",
        "14": "<p><strong>ki hineni meqim alechem goy</strong> — &quot;for I am raising up a nation against you.&quot; The participle again signals immediacy. From the entrance of Hamath to the Brook of the Arabah describes the full extent of the land — what the nation shall oppress is not a portion of Israel but its entirety. The nation is unnamed (Assyria), which heightens the threat: the identity of the instrument matters less than the certainty of the divine agency behind it.</p>"
    },
    "7": {
        "1": "<p><strong>koh her&apos;ani Adonai YHWH</strong> — &quot;This is what the Lord YHWH showed me.&quot; The vision report formula (<em>koh her&apos;ani</em>) marks the transition to the five-vision cycle (7:1-9:4). The first vision: locusts forming at the beginning of the late crop — the <em>leqesh</em> (late planting) after the king&apos;s first mowing. The timing is critical: the king&apos;s portion has been taken, leaving only the late crop to sustain the population. The locusts threaten total consumption of what little remains.</p>",
        "2": "<p><strong>va-yhi im killa le-echol et esev ha-aretz</strong> — &quot;when they had finished eating the grass of the land.&quot; Amos intercedes: &quot;O Lord YHWH, please forgive — how can Jacob stand? He is so small!&quot; (<em>ki qaton hu</em>). The intercession acknowledges Israel&apos;s vulnerability and smallness — not its righteousness. The appeal is to divine mercy, not covenant merit. YHWH relents (<em>nacham</em>, a divine change of disposition in response to intercession): &quot;It shall not be.&quot;</p>",
        "3": "<p><strong>va-yinachem YHWH al-zot</strong> — &quot;YHWH relented concerning this.&quot; Divine relenting (<em>nacham</em> niphal) is a recurring motif in the prophets — a genuine responsiveness of YHWH to prophetic intercession. The decree is provisional, not absolute; it can be withheld when a mediator stands in the breach. The first vision ends with the judgment averted. The repetition of this pattern in v. 6 makes the third vision&apos;s lack of relenting (v. 8) all the more decisive.</p>",
        "4": "<p><strong>koh her&apos;ani Adonai YHWH</strong> — Second vision: fire called by YHWH for judgment, consuming the great deep (<em>tehom rabbah</em>) and devouring the land (<em>haheleq</em>, possibly the agricultural allotment). The scope is cosmic — the subterranean waters that sustain the earth are consumed. Again Amos intercedes with the same formula: &quot;O Lord YHWH, please stop — how can Jacob stand? He is so small!&quot;</p>",
        "5": "<p><strong>YHWH Elohim sh&apos;lach-na</strong> — &quot;O Lord YHWH, please stop.&quot; The second intercession uses a different verb: <em>chadal</em> (cease, stop) rather than <em>s&apos;lach</em> (forgive) from v. 2. The slight variation may reflect escalation — the second vision&apos;s destruction is cosmic in scale, and the request is simply for cessation. YHWH again relents: &quot;This also shall not be.&quot;</p>",
        "6": "<p><strong>nacham YHWH al-zot</strong> — &quot;YHWH relented concerning this.&quot; The second relenting mirrors the first. Two intercessions, two retractions. The pattern makes the third vision structurally climactic — when YHWH holds his ground and refuses to relent (v. 8), the reader understands that a threshold has been crossed.</p>",
        "7": "<p><strong>ve-hineh Adonai nitzav al-chomat anakh</strong> — &quot;the Lord was standing beside a wall built true to plumb, with a plumb line (<em>anakh</em>) in his hand.&quot; <em>Anakh</em> is likely an Akkadian loanword (<em>anakku</em> = lead or tin) — its rarity lends the vision particularity. The wall has been built true; YHWH is measuring with the same standard Israel was built to. The plumb line is not an instrument of construction now but of judgment — measuring existing reality against the original standard.</p>",
        "8": "<p><strong>mah atah ro&apos;eh Amos</strong> — &quot;What do you see, Amos?&quot; The divine question elicits the prophetic report. YHWH declares: &quot;I am setting a plumb line (<em>anakh</em>) in the midst of my people Israel. I will never again pass over them (<em>lo osif od avor lo</em>).&quot; The phrase &quot;pass over&quot; (<em>avor</em>) may carry the resonance of the Exodus passover — YHWH who once passed over Israel to protect them will now pass through for judgment. The high places of Isaac and the sanctuaries of Israel will be desolated.</p>",
        "9": "<p><strong>ve-qamti al beit Yaravam b&apos;cherev</strong> — &quot;I will rise against the house of Jeroboam with the sword.&quot; The plumb line vision concludes with a specific dynastic threat against Jeroboam II. This specific political prediction is what triggers Amaziah&apos;s report to Jeroboam and his confrontation with Amos in the following section. The connection between visionary oracle and political reaction is direct.</p>",
        "10": "<p><strong>va-yishlach Amazyahu kohen Beit-El el-Yaravam</strong> — &quot;Amaziah, the priest of Bethel, sent to Jeroboam.&quot; Amaziah is the royal priest of the state sanctuary at Bethel — Jeroboam I&apos;s anti-Jerusalem alternative to Temple worship. His accusation: Amos has conspired (<em>qashar</em>) against Jeroboam in the midst of the house of Israel. The charge of conspiracy is political, transforming prophetic proclamation into sedition. &quot;The land is not able to bear all his words&quot; — <em>lo tuchal ha-aretz le-hacil et kol devarav</em> — the prophetic speech is too heavy for the political order to sustain.</p>",
        "11": "<p><strong>ki koh amar Amos</strong> — &quot;for thus Amos said.&quot; Amaziah quotes — and slightly misquotes — Amos&apos;s message: &quot;Jeroboam shall die by the sword, and Israel must go into exile away from its land.&quot; The reported speech may compress several oracles. Whether accurate or not, the summary captures the essence of Amos&apos;s threat, which is the real reason for expulsion.</p>",
        "12": "<p><strong>va-yomer Amazyahu el-Amos</strong> — &quot;Amaziah said to Amos.&quot; The command to leave has economic and territorial rationale: &quot;Go to the land of Judah — eat bread there and prophesy there.&quot; &quot;Eat bread there&quot; implies that prophesying was a paid profession — Amaziah assumes Amos is a professional prophet pursuing his trade in the wrong market. The royal sanctuary at Bethel belongs to the crown and has no room for unauthorized proclamation.</p>",
        "13": "<p><strong>u-v&apos;Beit-El lo tosif od le-hinnavei</strong> — &quot;at Bethel you shall not prophesy again.&quot; The finality of the prohibition frames the encounter as an institutional suppression of prophetic speech. Bethel is &quot;the king&apos;s sanctuary and a royal house (<em>beit mamlakhah</em>)&quot; — state religion explicitly serving the political order. The alignment of sanctuary with palace is the structural problem Amos&apos;s entire ministry exposes.</p>",
        "14": "<p><strong>lo navi anochi</strong> — &quot;I am not a prophet.&quot; Amos&apos;s self-identification is one of the most debated in the OT. He disclaims being a <em>navi</em> (prophet) or a <em>ben navi</em> (son of a prophet, member of prophetic guild). He was a <em>boqer</em> (herdsman; the word may denote a specific type of cattle-raiser) and a <em>boles shiqmim</em> (dresser of sycamore figs — one who nicks the fig to accelerate ripening, a task associated with the poor). The disclaimer distinguishes Amos from professional prophets who prophesy for hire.</p>",
        "15": "<p><strong>va-yiqacheni YHWH me-achar ha-tzon</strong> — &quot;YHWH took me from following the flock.&quot; Amos&apos;s authority derives entirely from divine calling, not professional standing. The verb <em>laqach</em> (take) is the same used for the charismatic seizure of prophets and leaders throughout the OT — it is the act of divine appropriation that creates a messenger. The legitimacy of his prophetic speech rests on the One who sent him, not on any institutional credential.</p>",
        "16": "<p><strong>atah shema devar YHWH</strong> — &quot;Now hear the word of YHWH.&quot; Turning Amaziah&apos;s expulsion command back, Amos delivers a specific judgment oracle against the priest himself. The oracle addresses what Amaziah tried to silence — and silencing is precisely the transgression that triggers the personal judgment.</p>",
        "17": "<p><strong>ishtekha ba-ir tizneh</strong> — &quot;Your wife shall become a prostitute in the city.&quot; The judgment on Amaziah mirrors his institutional sin: he tried to silence the covenant voice at the royal sanctuary; his judgment includes the desecration of everything he protected — his wife dishonored, his children killed, his land divided by survey line (<em>be-chevel yechulag</em>), himself dying in a foreign unclean land. The priest of Israel&apos;s most prominent sanctuary will die in exile on impure soil. &quot;Israel shall surely go into exile away from its land&quot; — Amaziah&apos;s personal judgment is the microcosm of the national judgment.</p>"
    },
    "8": {
        "1": "<p><strong>koh her&apos;ani Adonai YHWH</strong> — Fourth vision: a basket of summer fruit (<em>kelub qayits</em>). <em>Qayits</em> (summer fruit, often figs at the end of the season) sets up one of Amos&apos;s most striking wordplays. The vision is presented and interpreted in immediate sequence — no intercession, no divine relenting.</p>",
        "2": "<p><strong>ba ha-qetz el-ami Yisrael</strong> — &quot;The end (<em>qetz</em>) has come upon my people Israel.&quot; The pun: <em>qayits</em> (summer fruit) sounds like <em>qetz</em> (end, termination). Summer fruit signals the end of the growing season — the last harvest before winter. The end the fruit announces is Israel&apos;s own termination. &quot;I will never again pass over them&quot; repeats the verdict of 7:8 — the pattern of relenting is definitively closed.</p>",
        "3": "<p><strong>ve-heylu shirot heikhal ba-yom hahu</strong> — &quot;the songs of the temple shall become wailing (<em>yeyalilu</em>) in that day.&quot; The liturgical songs that fill the sanctuary will become death-wail. The many corpses thrown everywhere and the command &quot;silence!&quot; (<em>has</em>) repeats the terror-silence of 6:10 — the name of YHWH too dangerous to invoke, the dead too many to count.</p>",
        "4": "<p><strong>shim&apos;u zot ha-sho&apos;afim evyon</strong> — &quot;Hear this, you who trample the needy.&quot; The indictment pivot. <em>Sha&apos;af</em> (trample, pant after, crush) — the merchant class panting with desire for the poor to be economically consumed. They wait for the new moon to end and the sabbath to pass so commerce can resume — the sacred calendar is an obstacle to profit, not a structure for life.</p>",
        "5": "<p><strong>lehaqtin eifah u-le-hagdil shekel</strong> — &quot;making the ephah small and the shekel great.&quot; The <em>eifah</em> is the dry measure for grain — shrinking it means the customer gets less. The <em>shekel</em> is the weight for silver — inflating it means the price paid is higher. Both instruments of trade are falsified simultaneously. The <em>moznei mirma</em> (deceitful scales) complete the picture: every mechanism of exchange is corrupted from within.</p>",
        "6": "<p><strong>likhnot ba-kesef dalim</strong> — &quot;buying the poor for silver.&quot; The accumulation of economic injustice culminates in debt slavery. The needy is sold for a pair of sandals — the same image as 2:6, forming an inclusio around the book&apos;s first major indictment section. Even the waste of the wheat (<em>mappal bar</em> — husks, chaff, or spoiled grain) is sold to the poor: they receive refuse at inflated prices.</p>",
        "7": "<p><strong>nishba YHWH b&apos;ge&apos;on Yaakov</strong> — &quot;YHWH swears by the pride of Jacob.&quot; In 6:8 the pride of Jacob is the object of divine abhorrence; here it is the instrument of the divine oath. The use of <em>ge&apos;on Yaakov</em> as a swearing-formula may be ironic — YHWH swears by what Israel is most proud of precisely because that pride is what is being judged. The oath guarantees: &quot;I will never forget any of their deeds.&quot;</p>",
        "8": "<p><strong>ha-al zot lo tirgaz ha-aretz</strong> — &quot;shall not the land tremble on account of this?&quot; The cosmic response to injustice is seismic: the earth shaking, rising and sinking like the Nile in flood. The Nile comparison (<em>ka-ye&apos;or Mitzrayim</em>) invokes the Egyptian context — the same land from which YHWH redeemed Israel becomes the image for Israel&apos;s judgment-upheaval.</p>",
        "9": "<p><strong>ve-haya ba-yom hahu</strong> — &quot;it shall be on that day.&quot; The Day of the LORD imagery intensifies: <em>hashshi ha-shemesh ba-tzaharayim</em> — &quot;I will make the sun go down at noon.&quot; Solar darkening at midday inverts the normal order of daylight. &quot;I will darken the earth on a bright day&quot; — the language echoes the Egyptian plague of darkness and anticipates eschatological Day of the LORD imagery in the prophets and NT.</p>",
        "10": "<p><strong>ve-hafakhti chageikhem l&apos;evel</strong> — &quot;I will turn your feasts into mourning.&quot; The covenant feasts (<em>chagim</em>) are inverted to grief. The mourning becomes like that for an <em>yachid</em> (only son) — the most acute grief Israel knew. The &quot;bitterest of days&quot; (<em>ke-yom marah</em>) closes the chiasm: what was festive becomes funereal, what was sacred becomes sorrowful.</p>",
        "11": "<p><strong>hineh yamim ba&apos;im</strong> — &quot;behold, days are coming.&quot; The eschatological formula signals the culminating punishment: a famine of the word of YHWH. Not bread or water but <em>davar YHWH</em> — the oracular, authoritative, covenantal speech of God. Having rejected the word Amos proclaimed, Israel will search for it everywhere and find nothing. The withdrawal of prophetic speech is itself the judgment.</p>",
        "12": "<p><strong>ve-nau mi-yam ad yam</strong> — &quot;they shall wander from sea to sea.&quot; The geography of desperation: from west to east, from north to south (Dan to Beersheba in reverse), seeking the word of YHWH. The verb <em>nua</em> (wander, totter, stagger) suggests aimless, unmoored movement — the covenant community without prophetic guidance has lost its organizing center.</p>",
        "13": "<p><strong>ba-yom hahu titalafna ha-betulot ha-yafot</strong> — &quot;in that day the beautiful young women (<em>betulot</em>) and the young men shall faint.&quot; The thirst described is for the word of YHWH (v. 11) — spiritual desolation expressed as physical exhaustion. Those in the prime of life, who should have the most vitality, are the ones who collapse. The thirst for divine speech that will not come is more enfeebling than physical thirst.</p>",
        "14": "<p><strong>ha-nishba&apos;im b&apos;ashmat Shomron</strong> — &quot;those who swear by the shame of Samaria.&quot; <em>Ashmat Shomron</em> may be a deliberate deformation of the divine name or a reference to a specific pagan deity worshipped there (possibly Ashimah — cf. 2 Kings 17:30). Swearing &quot;by the way of Beersheba&quot; suggests pilgrimage to a southern sanctuary as a form of religiosity divorced from covenant fidelity. These devotees of false shrines &quot;shall fall and not rise again&quot; — a fall with no restoration available.</p>"
    },
    "9": {
        "1": "<p><strong>ra&apos;iti et Adonai nitzav al-ha-mizbeach</strong> — &quot;I saw the Lord standing beside the altar.&quot; The fifth and final vision is unique: YHWH is standing by the altar himself, not showing Amos a symbolic image. The command — &quot;Strike the capital (<em>kapitor</em>) so that the thresholds shake&quot; — is directed at the sanctuary itself. The sanctuary that was meant to be the meeting point of heaven and earth becomes the site of judgment. <em>Kapitor</em> (capital of a column) may also evoke Caphtor (Crete), the origin point of the Philistines — a further irony in a verse addressed to Israel at the Bethel sanctuary.</p>",
        "2": "<p><strong>im yachteru bishol</strong> — &quot;if they dig down to Sheol.&quot; The escape-impossibility litany: digging to the underworld, climbing to heaven, hiding on Carmel&apos;s summit, concealing at the bottom of the sea. Each potential refuge is foreclosed. The hand of YHWH reaches every cosmic zone — below, above, horizontal extremes. This is not a celebration of divine omnipresence but a judgment-announcement of inescapability. The language echoes Psalm 139, which celebrates the same divine omnipresence as comfort; here it is terror.</p>",
        "3": "<p><strong>im ye-chave&apos;u be-rosh ha-Karmel</strong> — &quot;if they hide themselves on top of Carmel.&quot; The dense forests of Carmel were the most impenetrable terrain in Israel. Even there, YHWH will search and take them. If they go to the floor of the sea, he will command the serpent (<em>nachash</em>, the chaos-dragon associated with the deep) to bite them. Every hiding place, natural or mythological, is accessible.</p>",
        "4": "<p><strong>ve-im yelku va-shevi lifnei oyvehem</strong> — &quot;if they go into captivity before their enemies.&quot; Even exile — the final escape attempt — is not escape. YHWH will command the sword there. The final declaration reverses the Aaronic blessing: &quot;I will set my eyes on them for harm and not for good.&quot; The divine face that was invoked to shine on Israel (Num 6:25) is now fixed on them in judgment.</p>",
        "5": "<p><strong>va-Adonai YHWH ha-tzva&apos;ot</strong> — &quot;the Lord YHWH of hosts.&quot; The doxology (vv. 5-6) interrupts the judgment sequence with a cosmic hymn. YHWH who touches the earth so it melts, who builds his upper chambers in the heavens and founds his vault upon the earth — this is the One executing the judgment. The doxology answers the implied question: who could carry out such comprehensive judgment? The One who structured the cosmos.</p>",
        "6": "<p><strong>ha-boneh ba-shamayim ma&apos;alotav</strong> — &quot;who builds his upper chambers in the heavens.&quot; The cosmic architecture imagery: YHWH&apos;s upper chambers (<em>ma&apos;alot</em>, steps/stories) in the heavens, his vault founded upon the earth, calling for the waters of the sea and pouring them upon the face of the earth. <em>YHWH shemo</em> — &quot;YHWH is his name&quot; — closes the doxology with the divine name as the ultimate credential.</p>",
        "7": "<p><strong>ha-lo chitziim atem li b&apos;nei Yisrael</strong> — &quot;Are you not like the Cushites to me, O people of Israel?&quot; A radical challenge to election privilege. The Exodus was not Israel&apos;s unique credential — YHWH also brought up the Philistines from Caphtor and the Arameans from Kir. The implication is not that the Exodus was meaningless but that election does not guarantee immunity from judgment. Covenant relationship intensifies accountability rather than suspending it.</p>",
        "8": "<p><strong>hineh einei Adonai YHWH ba-mamlakhah ha-chata&apos;ah</strong> — &quot;the eyes of the Lord YHWH are upon the sinful kingdom.&quot; The distinction between nation and remnant appears: the sinful kingdom (institutional Israel as a political entity) will be destroyed, but YHWH will &quot;not utterly destroy the house of Jacob.&quot; The two clauses hold judgment and preservation in tension — total dissolution of the present political structure, but not total extinction of the covenanted people.</p>",
        "9": "<p><strong>ki hineh anochi metzaveh</strong> — &quot;for I am commanding.&quot; The sifting (<em>va-nifoti</em>) metaphor: Israel shaken among the nations like grain in a sieve (<em>kebara</em>), but no pebble (<em>tzror</em>) will fall to the ground. The metaphor is complex: the sieve retains the stones (the guilty who will be destroyed) while the grain (the righteous remnant) passes through to safety. The sifting is the mechanism of judgment that simultaneously preserves.</p>",
        "10": "<p><strong>ba-cherev yamutu kol chata&apos;ei ami</strong> — &quot;all the sinners of my people shall die by the sword.&quot; The criterion for inclusion in judgment: those who say &quot;Evil shall not overtake or confront us.&quot; The self-exemption from judgment is itself the defining sin of the complacent (cf. 6:3). Those who refused to take the covenant lawsuit seriously will find it executed against them.</p>",
        "12": "<p><strong>le-ma&apos;an yireshu et she&apos;erit Edom</strong> — &quot;that they may possess the remnant of Edom.&quot; The MT reads <em>Edom</em>; the LXX reads <em>anthropon</em> (humanity/Adam). Acts 15:17 follows the LXX in James&apos;s speech, citing this verse to support Gentile inclusion in the restored people. The divergence is theologically generative: MT promises Israel&apos;s possession of neighboring territory; LXX promises the nations (all of humanity) seeking the Lord. The NT application uses the LXX&apos;s universalizing reading as scriptural grounding for the Gentile mission.</p>",
        "13": "<p><strong>hineh yamim ba&apos;im</strong> — &quot;behold, days are coming.&quot; The eschatological reversal: the plowman overtakes the reaper, the grape-treader overtakes the one who sows seed. Agriculture in reverse — the cycle so accelerated that harvesting and planting overlap. Mountains dripping new wine (<em>assis</em>, grape juice), hills flowing with it — the language of superabundant blessing that inverts the drought and famine of the judgment oracles.</p>",
        "14": "<p><strong>ve-shavti et shevut ami Yisrael</strong> — &quot;I will restore the fortunes of my people Israel.&quot; <em>Shavti et shevut</em> is the classic restoration formula — often translated &quot;restore the captivity/fortunes&quot; but functioning as an idiom for comprehensive reversal of all that has gone wrong. They will build ruined cities and inhabit them, plant vineyards and drink their wine, make gardens and eat their fruit. The specific activities named reverse the dispossession and exile that judgment brought.</p>",
        "15": "<p><strong>u-netativ al adamatam</strong> — &quot;I will plant them on their land.&quot; The closing image is rooted and permanent: &quot;they shall never again be uprooted from the land that I have given them.&quot; The verb <em>nata</em> (plant) echoes the planting of a vine or tree — permanent, rooted, not subject to exile. The final word of Amos is not judgment but the covenant fidelity of YHWH who planted Israel and will not permit permanent uprooting. <em>YHWH Eloheicha amar</em> — &quot;says the LORD your God&quot; — the covenant formula as final seal.</p>"
    }
}

def main():
    existing = load_comm('mkt-original', 'amos')
    merge_comm(existing, AMOS)
    save_comm('mkt-original', 'amos', existing)
    print('Amos 6-9 mkt-original written.')

if __name__ == '__main__':
    main()
